PREFIX pl: <https://ontorag.dev/ns/pure_land#>
PREFIX dcterms: <http://purl.org/dc/terms/>
SELECT ?id WHERE { pl:T0360 dcterms:identifier ?id . }

PREFIX pl: <https://ontorag.dev/ns/pure_land#>
PREFIX dcterms: <http://purl.org/dc/terms/>
SELECT ?c WHERE { pl:T0360 dcterms:creator ?c . }

PREFIX pl: <https://ontorag.dev/ns/pure_land#>
PREFIX skos: <http://www.w3.org/2004/02/skos/core#>
SELECT ?alt WHERE { pl:Amitabha skos:altLabel ?alt . FILTER(LANG(?alt) = 'en') }

PREFIX pl: <https://ontorag.dev/ns/pure_land#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?l WHERE { ?c pl:contemplationOrder 1 ; rdfs:label ?l . FILTER(LANG(?l) = 'ko') }

PREFIX pl: <https://ontorag.dev/ns/pure_land#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?l WHERE { pl:LotusPond_Canonical rdfs:label ?l . FILTER(LANG(?l) = 'zh-Hant') }

